INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'c5b014e6-0da0-4608-8a25-17ea6a6d02bf', E'fe27ac4a-192b-45c8-aee7-bf0feaa00a7f', E'What is a Functional Dependency?', E'Relationship between tables', E'When X uniquely determines Y', E'A type of JOIN', E'Constraint on data types', E'B', E'X→Y means X uniquely determines Y.', E'1', E'6') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'7bf13270-f2a8-45cd-863f-e9b03dca189b', E'fe27ac4a-192b-45c8-aee7-bf0feaa00a7f', E'Denormalization is done for:', E'Better integrity', E'Performance optimization', E'Reducing tables', E'Best practices', E'B', E'Denormalization improves read performance.', E'1', E'7') ON CONFLICT (id) DO NOTHING;
