INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'9e11c46c-d9ec-4eec-9d10-a5d78b86da75', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'Transaction states are:', E'Start, Run, Stop', E'Active, Partially Committed, Committed, Failed, Aborted', E'Begin, Process, End', E'Open, Closed, Pending', E'B', E'Active → Partially Committed → Committed (or Failed → Aborted).', E'1', E'1') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'9ff1bb5e-1b66-4775-a922-914292c89d8b', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'A "Dirty Read" occurs when:', E'Data is corrupted', E'An uncommitted value is read', E'A transaction reads own data', E'Query returns empty', E'B', E'Dirty read: reading uncommitted data from another transaction.', E'1', E'2') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'8d0c6d1c-aa26-4975-836f-ded732259e2e', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'Which isolation level prevents all issues?', E'Read Uncommitted', E'Read Committed', E'Repeatable Read', E'Serializable', E'D', E'Serializable is the strictest isolation level.', E'1', E'3') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'eef87f5d-b2f5-477b-aeba-51065da10653', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'Exclusive Lock (X) allows:', E'Multiple reads', E'Multiple writes', E'Only one transaction to read/write', E'No access', E'C', E'Exclusive lock: only the holding transaction can access.', E'1', E'4') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'3a0725f1-ada5-40d5-bea9-bdb1ed2b7fa6', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'What is a deadlock?', E'Slow query', E'Database crash', E'Transactions waiting for each other', E'Data corruption', E'C', E'Deadlock: transactions waiting for each other indefinitely.', E'1', E'5') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'e2569032-b149-4673-a4cf-9f07fba0d225', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'Two-Phase Locking phases:', E'Read and Write', E'Growing and Shrinking', E'Lock and Unlock', E'Commit and Rollback', E'B', E'2PL: Growing (acquire locks) and Shrinking (release locks).', E'1', E'6') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'331984ba-fc9d-404e-8c4b-e377515fc13e', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'Write-Ahead Logging (WAL) ensures:', E'Atomicity', E'Isolation', E'Durability', E'Consistency', E'C', E'WAL ensures durability by writing logs before data changes.', E'1', E'7') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'b4e5f265-a296-4889-ad0d-261fee1e5d15', E'6f6d8143-e36e-4c96-b0d1-115a7265b640', E'In Wait-Die, a younger transaction:', E'Waits', E'Dies (aborts)', E'Continues', E'Restarts', E'B', E'Wait-Die: younger transaction aborts if needing a lock from older.', E'1', E'8') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'818b8d94-face-43fa-8ea1-cd8019347c8c', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'A university database has: Student(SID, Name, DeptID), Department(DeptID, DeptName, HOD_ID), Faculty(FID, Name). The functional dependencies are: SID→Name,DeptID; DeptID→DeptName,HOD_ID; FID→Name. The Student table is in which normal form?', E'1NF — because it has repeating groups', E'2NF — because all non-key attributes depend on the full primary key', E'3NF — because there are no transitive dependencies in Student', E'BCNF — because every determinant is a superkey', E'C', E'Student(SID→Name,DeptID) has SID as the only candidate key. Name and DeptID both depend directly on SID with no transitive dependency within this table. DeptID→DeptName,HOD_ID is a dependency in the Department table, not Student. So Student is in 3NF.', E'2', E'1') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'aa3a6f92-a95b-4715-8932-a2f1741a7ef5', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'Consider two transactions: T1 reads A, writes A, reads B, writes B. T2 reads A, reads B, writes B. Schedule: T1:R(A), T2:R(A), T1:W(A), T2:R(B), T1:R(B), T1:W(B), T2:W(B). Is this schedule conflict-serializable?', E'Yes, it is equivalent to T1→T2', E'Yes, it is equivalent to T2→T1', E'No, because the precedence graph has a cycle', E'Cannot be determined without knowing the values', E'C', E'Build precedence graph: T1:R(A) before T2:R(A) — no conflict (both reads). T2:R(A) before T1:W(A) — conflict: T2→T1. T1:R(B) before T2:W(B) — conflict: T1→T2. This creates a cycle T1→T2→T1, so NOT conflict-serializable.', E'2', E'2') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'cb197d4e-656b-4674-b0f4-01646c06e0af', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'A B+ tree of order 4 (max 3 keys per node) contains values 1-15 inserted in order. After deleting keys 5, 7, and 11, what is the minimum height of the resulting tree?', E'1 (just root with children)', E'2 (root, one level of internal nodes, leaves)', E'3 (three levels)', E'0 (all data fits in root)', E'B', E'With 12 remaining values in a B+ tree of order 4, each leaf can hold 2-3 keys. Minimum leaves needed = ceil(12/3) = 4 leaves. An internal node can hold 2-4 children. 4 leaves need at least 2 internal nodes under a root, giving height = 2.', E'1', E'3') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'd3097def-8622-4639-9ad8-6b4e0092ff43', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'Given relation R(A,B,C,D,E) with FDs: A→BC, CD→E, B→D, E→A. What are all the candidate keys?', E'A only', E'A and E', E'A, E, BC, and CD', E'A, E, and CD', E'C', E'A→BC→D(via B→D), and CD→E, so A→ABCDE (A is a candidate key). E→A→ABCDE (E is a candidate key). BC: B→D, so BC→BCD, CD→E, so BC→BCDE, E→A, so BC→ABCDE. CD: CD→E→A→BC, so CD→ABCDE. All four are candidate keys.', E'2', E'4') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'c79ff371-2e22-420e-abfd-34de836448cf', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'In a distributed database, a transaction T needs to update records on servers S1, S2, and S3. During 2-Phase Commit, S1 votes YES, S2 votes YES, but S3 crashes before voting. What should the coordinator do?', E'Commit the transaction on S1 and S2, abort on S3', E'Wait indefinitely for S3 to recover and vote', E'Abort the entire transaction (global abort)', E'Commit because majority voted YES', E'C', E'In 2PC, ALL participants must vote YES for a commit. If any participant fails to vote (or votes NO), the coordinator must issue a global ABORT. 2PC requires unanimity, not majority.', E'1', E'5') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'5d982f05-4279-4893-b8f8-efbe488d355a', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'A query "SELECT * FROM Employees WHERE salary > 50000 AND department = ''CS'' ORDER BY name" runs on a table with 100,000 rows. An index exists on (department, salary). Which optimization would the query optimizer most likely choose?', E'Full table scan with filesort', E'Use the composite index for department="CS", then filter salary, then filesort for name', E'Use the index for salary > 50000 only', E'Create a temporary index on name, then scan', E'B', E'The composite index (department, salary) can be used to efficiently find department="CS" rows (first column match), then the index can further narrow by salary > 50000 (range on second column). The ORDER BY name would require a filesort since name is not in the index. This is the most efficient plan.', E'1', E'6') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'25b53e30-7f52-4f50-bc5a-30a7f5da7ccb', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'A table OrderDetails(OrderID, ProductID, Qty, Price, Total) has Total = Qty × Price. Which anomaly does storing Total introduce, and what is the best fix?', E'Insertion anomaly — add a CHECK constraint', E'Update anomaly — use a computed/generated column or view', E'Deletion anomaly — add a trigger', E'No anomaly — storing derived data is always fine', E'B', E'Total is a derived attribute (Qty × Price). Storing it creates an UPDATE anomaly: if Qty or Price changes, Total must also be updated or it becomes inconsistent. The best fix is to use a computed column (generated as Qty*Price) or a view, so Total is always calculated, never stored.', E'1', E'7') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'2bb4b872-4ead-4d4d-980e-c1f3af04bb73', E'6708e7a5-b312-4a77-8784-241c3d91039a', E'Two transactions execute under Strict 2PL: T1 holds X-lock on record R1 and requests S-lock on R2. T2 holds X-lock on R2 and requests S-lock on R1. What happens?', E'Both transactions proceed normally', E'Deadlock occurs — one transaction must be rolled back', E'T1 proceeds, T2 waits', E'Both requests are converted to X-locks', E'B', E'T1 holds X(R1), wants S(R2) — but T2 holds X(R2), so T1 must wait. T2 holds X(R2), wants S(R1) — but T1 holds X(R1), so T2 must wait. Circular wait = deadlock. The DBMS deadlock detector must abort one transaction.', E'2', E'8') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'2fa86e52-d021-4398-9570-a51fea7aa14d', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'Given: Employees(EID, Name, DeptID, Salary, MgrID). Write the correct query to find departments where the average salary exceeds the company-wide average salary. Which query is correct?', E'SELECT DeptID FROM Employees GROUP BY DeptID HAVING AVG(Salary) > AVG(Salary)', E'SELECT DeptID FROM Employees GROUP BY DeptID HAVING AVG(Salary) > (SELECT AVG(Salary) FROM Employees)', E'SELECT DeptID FROM Employees WHERE AVG(Salary) > (SELECT AVG(Salary) FROM Employees)', E'SELECT DeptID, AVG(Salary) FROM Employees HAVING AVG(Salary) > ALL(SELECT AVG(Salary) FROM Employees)', E'B', E'Option B correctly uses a correlated subquery in HAVING. Option A compares AVG with itself (always false). Option C uses AVG in WHERE (not allowed). Option D has syntax issues with GROUP BY missing.', E'1', E'1') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'fccefdbf-50f1-4bc4-861d-1d50da9a7e85', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'What is the output of: SELECT COUNT(*), COUNT(commission) FROM employees; if the table has 10 rows and 3 rows have NULL commission?', E'10, 10', E'10, 7', E'7, 7', E'10, 3', E'B', E'COUNT(*) counts ALL rows including NULLs = 10. COUNT(commission) counts only non-NULL values = 10-3 = 7. This is a key distinction in SQL aggregate functions.', E'1', E'2') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'41ff0de5-ed94-426f-a715-90d55e511c85', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'To find employees who earn more than EVERY employee in department 10, which operator should be used?', E'salary > ANY (SELECT salary FROM emp WHERE dept=10)', E'salary > ALL (SELECT salary FROM emp WHERE dept=10)', E'salary > SOME (SELECT salary FROM emp WHERE dept=10)', E'salary IN (SELECT MAX(salary) FROM emp WHERE dept=10)', E'B', E'> ALL means greater than the maximum value in the subquery result. > ANY/SOME means greater than at least one (the minimum). To beat EVERY employee in dept 10, we need > ALL.', E'1', E'3') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'4092f450-9e2e-4847-806e-a68ca185dcbf', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'What does this query return? SELECT e1.Name FROM Employees e1 WHERE NOT EXISTS (SELECT 1 FROM Projects p WHERE NOT EXISTS (SELECT 1 FROM Works_On w WHERE w.EID = e1.EID AND w.PID = p.PID))', E'Employees who work on at least one project', E'Employees who work on no projects', E'Employees who work on ALL projects (division)', E'All employees regardless of projects', E'C', E'This is the relational division pattern in SQL. Double NOT EXISTS reads as: "find employees where there is NO project that they do NOT work on" = employees who work on ALL projects.', E'2', E'4') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'201c2664-97e6-4727-b424-c959a970b47f', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'Given a self-join query: SELECT e.Name AS Employee, m.Name AS Manager FROM Employees e LEFT JOIN Employees m ON e.MgrID = m.EID; — What does LEFT JOIN ensure here?', E'Only employees with managers are shown', E'All employees are shown, even those without a manager (CEO)', E'All managers are shown even if they have no reports', E'Duplicate rows are added for each manager', E'B', E'LEFT JOIN ensures ALL rows from the left table (employees) are included. If an employee has no matching MgrID (like a CEO), they still appear with NULL in the Manager column.', E'1', E'5') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'72347820-4a25-407d-b7e2-44e0fbc855f7', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'Which of these prevents SQL injection most effectively?', E'Escaping single quotes in user input', E'Using parameterized/prepared statements', E'Validating input length', E'Using LIMIT 1 in queries', E'B', E'Parameterized/prepared statements separate SQL code from data, making injection impossible. Escaping quotes can be bypassed. Input validation and LIMIT don''t prevent injection at the root cause.', E'1', E'6') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'258d2dcf-9d1f-41eb-b177-600489fbfc05', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'A query runs: SELECT dept, salary, RANK() OVER (PARTITION BY dept ORDER BY salary DESC) as rnk FROM employees; — What does RANK() return for two employees with the same highest salary in a department?', E'Both get rank 1, next gets rank 2', E'Both get rank 1, next gets rank 3', E'First gets rank 1, second gets rank 2', E'Both get rank 0', E'B', E'RANK() assigns the same rank for ties and SKIPS the next rank(s). Two employees tied at rank 1, so the next employee gets rank 3 (not 2). DENSE_RANK() would give rank 2 instead.', E'1', E'7') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'b0b99dd5-02a4-438b-ae2e-0945b814437a', E'68a0660c-d050-41a0-9646-c6a9418ea397', E'What is wrong with this query? DELETE FROM orders WHERE order_date < "2024-01-01" AND customer_id IN (SELECT customer_id FROM orders WHERE total > 1000)', E'Cannot use subquery in DELETE', E'The subquery references the same table being deleted (may cause issues in MySQL)', E'AND cannot combine with IN', E'Nothing is wrong', E'B', E'In MySQL, you cannot modify a table and select from the same table in a subquery within the same statement. This throws an error. Solution: use a derived table/CTE, or a temporary table. PostgreSQL handles this correctly though.', E'2', E'8') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'70f94bb6-f96c-4815-b38c-41309fc2bb8d', E'183a7651-35d2-4664-9695-8f857c938f05', E'What is SQL Injection?', E'A way to secure databases', E'A code injection technique that might destroy your database', E'A database type', E'None of the above', E'B', E'SQLi is a security vulnerability.', E'1', E'1') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'f1d21ddc-93f0-4418-b32c-35d083be09ec', E'183a7651-35d2-4664-9695-8f857c938f05', E'How to prevent SQL Injection?', E'Use raw queries', E'Use prepared statements', E'Use simple string concatenation', E'Don''t use databases', E'B', E'', E'1', E'2') ON CONFLICT (id) DO NOTHING;
INSERT INTO public.questions (id, quiz_id, question_text, option_a, option_b, option_c, option_d, correct_option, explanation, points, sort_order) VALUES (E'5de22877-f5a9-4dbe-b2a3-dbaebe1a0a38', E'73243dfc-bfae-4886-beb9-14306af7b240', E'What is normalization in DBMS?', E'Process of organizing data to reduce redundancy', E'Process of data backup', E'Data encryption method', E'Data visualization technique', E'A', E'', E'1', E'1') ON CONFLICT (id) DO NOTHING;
